use aiken/crypto.{blake2b_224}
use aiken/fuzz
use aiken/primitive/bytearray
use cardano/fuzz as cfuzz
use cardano/transaction.{Transaction}

/// Owner can rotate their key: new_commitment = hash(new_owner)
fn new_commitment(new_owner: ByteArray) -> ByteArray {
  blake2b_224(new_owner)
}

/// Rotation is valid if old owner authorises AND new commitment is correct
fn rotation_valid(
  old_owner:      ByteArray,
  old_commitment: ByteArray,
  new_owner:      ByteArray,
  new_commitment_: ByteArray,
) -> Bool {
  blake2b_224(old_owner) == old_commitment
    && blake2b_224(new_owner) == new_commitment_
}

pub type VaultDatum {
  old_owner: ByteArray,
  commitment: ByteArray,
}

pub type VaultRedeemer {
  new_owner: ByteArray,
}

validator param_vault_rotation {
  spend(
    datum: Option<VaultDatum>,
    redeemer: VaultRedeemer,
    _ref,
    self: Transaction,
  ) {
    expect Some(d) = datum
    let new_com = new_commitment(redeemer.new_owner)
    let is_rotation = rotation_valid(
      d.old_owner,
      d.commitment,
      redeemer.new_owner,
      new_com,
    )
    let old_owner_signs =
      list.any(self.extra_signatories, fn(sig) { sig == d.old_owner })
    is_rotation && old_owner_signs
  }

  else(_) {
    fail
  }
}

use aiken/collection/list

// ── Property tests ───────────────────────────────────────────────────────────

test prop_rotation_valid_with_correct_keys(
  vals via fuzz.both(cfuzz.verification_key_hash(), cfuzz.verification_key_hash()),
) {
  let (old_owner, new_owner) = vals
  let old_com = blake2b_224(old_owner)
  let new_com = blake2b_224(new_owner)
  rotation_valid(old_owner, old_com, new_owner, new_com)
}

test prop_wrong_old_owner_fails(
  vals via fuzz.both(cfuzz.verification_key_hash(), cfuzz.verification_key_hash()),
) {
  let (old_owner, new_owner) = vals
  let old_com = blake2b_224(old_owner)
  let new_com = blake2b_224(new_owner)
  !rotation_valid(#"deadbeef", old_com, new_owner, new_com)
}

test prop_new_commitment_correct(
  owner via cfuzz.verification_key_hash(),
) {
  new_commitment(owner) == blake2b_224(owner)
}

test prop_different_owners_differ(
  owner via cfuzz.verification_key_hash(),
) {
  // owner vs its hash — almost certainly different lengths, different hashes
  let alt = bytearray.concat(owner, #"ff")
  new_commitment(owner) != new_commitment(alt)
}

use aiken/fuzz
use aiken/collection/list
use cardano/assets
use cardano/transaction.{Transaction, OutputReference}

/// Protocol fee collected on each fill (in bps)
fn fill_fee(fill_qty: Int, price: Int, fee_bps: Int) -> Int {
  fill_qty * price * fee_bps / 10000
}

/// Net proceeds to seller after fee deduction
fn seller_proceeds(fill_qty: Int, price: Int, fee_bps: Int) -> Int {
  fill_qty * price - fill_fee(fill_qty, price, fee_bps)
}

/// Fee is non-negative and less than gross proceeds
fn fee_valid(fill_qty: Int, price: Int, fee_bps: Int) -> Bool {
  let gross = fill_qty * price
  let fee   = fill_fee(fill_qty, price, fee_bps)
  fee >= 0 && fee < gross
}

// ── Property tests ───────────────────────────────────────────────────────────

test prop_zero_fee_bps_no_fee(
  vals via fuzz.both(fuzz.int_between(1, 1000), fuzz.int_between(1, 1000)),
) {
  let (qty, price) = vals
  fill_fee(qty, price, 0) == 0
}

test prop_seller_receives_less_than_gross(
  vals via fuzz.both(fuzz.int_between(1, 1000), fuzz.int_between(1, 100)),
) {
  let (qty, fee_bps) = vals
  let price = 100
  seller_proceeds(qty, price, fee_bps) < qty * price
}

test prop_fee_valid_for_standard_rate(
  vals via fuzz.both(fuzz.int_between(1, 1000), fuzz.int_between(1, 1000)),
) {
  let (qty, price) = vals
  fee_valid(qty, price, 30)
}

test prop_seller_proceeds_non_negative(
  vals via fuzz.both(fuzz.int_between(1, 1000), fuzz.int_between(1, 9999)),
) {
  let (qty, fee_bps) = vals
  seller_proceeds(qty, 100, fee_bps) >= 0
}

pub type OrderDatum {
  seller: ByteArray,
  fill_qty: Int,
  price: Int,
  fee_bps: Int,
  treasury: ByteArray,
}

pub type OrderRedeemer {
  Fill
  Cancel
}

validator order_fee_collection {
  spend(
    datum: Option<OrderDatum>,
    redeemer: OrderRedeemer,
    _ref: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum
    when redeemer is {
      Cancel ->
        list.any(self.extra_signatories, fn(sig) { sig == d.seller })
      Fill -> {
        let valid_fee = fee_valid(d.fill_qty, d.price, d.fee_bps)
        let proceeds  = seller_proceeds(d.fill_qty, d.price, d.fee_bps)
        let fee       = fill_fee(d.fill_qty, d.price, d.fee_bps)
        let seller_paid =
          list.any(
            self.outputs,
            fn(o) {
              assets.lovelace_of(o.value) >= proceeds && o.address.payment_credential == d.seller
            },
          )
        let treasury_paid =
          list.any(
            self.outputs,
            fn(o) {
              assets.lovelace_of(o.value) >= fee && o.address.payment_credential == d.treasury
            },
          )
        valid_fee && seller_paid && treasury_paid
      }
    }
  }

  else(_) {
    fail
  }
}

use aiken/fuzz
use aiken/collection/list
use cardano/assets
use cardano/transaction.{Transaction, OutputReference}

/// Liquidation penalty: liquidator pays debt and receives collateral + bonus
fn liquidation_bonus(collateral: Int, bonus_bps: Int) -> Int {
  collateral * bonus_bps / 10000
}

/// Liquidator receives: collateral + bonus
fn liquidator_receives(collateral: Int, bonus_bps: Int) -> Int {
  collateral + liquidation_bonus(collateral, bonus_bps)
}

/// Bonus is non-negative and bounded
fn bonus_in_range(collateral: Int, bonus_bps: Int) -> Bool {
  bonus_bps >= 0 && bonus_bps < 10000
    && liquidation_bonus(collateral, bonus_bps) >= 0
}

pub type LiquidationDatum {
  collateral_lovelace: Int,
  bonus_bps: Int,
  liquidator: ByteArray,
}

pub type LiquidationRedeemer {
  Liquidate
  Repay
}

validator liquidation {
  spend(
    datum: Option<LiquidationDatum>,
    redeemer: LiquidationRedeemer,
    _ref: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum
    when redeemer is {
      Liquidate -> {
        let signed =
          list.any(self.extra_signatories, fn(sig) { sig == d.liquidator })
        let min_out = liquidator_receives(d.collateral_lovelace, d.bonus_bps)
        let valid_bonus = bonus_in_range(d.collateral_lovelace, d.bonus_bps)
        let liquidator_paid =
          list.any(
            self.outputs,
            fn(o) {
              assets.lovelace_of(o.value) >= min_out
                && o.address.payment_credential == d.liquidator |> fn(_) { True }
            },
          )
        signed && valid_bonus && liquidator_paid
      }
      Repay -> list.any(self.extra_signatories, fn(sig) { sig == d.liquidator })
    }
  }

  else(_) {
    fail
  }
}

// ── Property tests ───────────────────────────────────────────────────────────

test prop_zero_bonus_receives_exact_collateral(
  collateral via fuzz.int_between(1, 100000),
) {
  liquidator_receives(collateral, 0) == collateral
}

test prop_bonus_increases_proceeds(
  vals via fuzz.both(fuzz.int_between(10000, 100000), fuzz.int_between(1, 500)),
) {
  let (collateral, bonus_bps) = vals
  liquidator_receives(collateral, bonus_bps) > collateral
}

test prop_bonus_non_negative(
  vals via fuzz.both(fuzz.int_between(1, 100000), fuzz.int_between(0, 500)),
) {
  let (collateral, bonus_bps) = vals
  liquidation_bonus(collateral, bonus_bps) >= 0
}

test prop_bonus_in_range_valid(
  collateral via fuzz.int_between(1, 100000),
) {
  bonus_in_range(collateral, 500)
}

use aiken/fuzz
use cardano/transaction.{Transaction, OutputReference}

/// Partial liquidation: liquidate only enough to restore health
/// Returns minimum debt to repay to reach target_ratio
fn min_repay_to_restore(
  collateral:   Int,
  debt:         Int,
  target_ratio: Int,
) -> Int {
  // Need: collateral * 100 >= new_debt * target_ratio
  // → new_debt <= collateral * 100 / target_ratio
  // → repay = debt - new_debt
  let max_debt = collateral * 100 / target_ratio
  if debt > max_debt { debt - max_debt } else { 0 }
}

/// After partial repayment, position is healthy
fn healthy_after_repay(
  collateral:   Int,
  debt:         Int,
  repay:        Int,
  target_ratio: Int,
) -> Bool {
  let new_debt = debt - repay
  new_debt > 0 && collateral * 100 >= new_debt * target_ratio
}

pub type LiquidationDatum {
  collateral: Int,
  debt: Int,
  target_ratio: Int,
  owner: ByteArray,
}

pub type LiquidationRedeemer {
  repay_amount: Int,
}

validator partial_liquidation {
  spend(
    datum: Option<LiquidationDatum>,
    redeemer: LiquidationRedeemer,
    _ref: OutputReference,
    self: Transaction,
  ) {
    expect Some(d) = datum
    let repay = redeemer.repay_amount
    let min_repay = min_repay_to_restore(d.collateral, d.debt, d.target_ratio)
    let position_restored =
      healthy_after_repay(d.collateral, d.debt, repay, d.target_ratio)
    let repay_sufficient = repay >= min_repay
    let signed_by_owner =
      list.any(self.extra_signatories, fn(sig) { sig == d.owner })
    signed_by_owner && repay_sufficient && position_restored
  }

  else(_) {
    fail
  }
}

// ── Property tests ───────────────────────────────────────────────────────────

use aiken/collection/list

test prop_no_repay_needed_when_healthy(
  vals via fuzz.both(fuzz.int_between(200, 500), fuzz.int_between(1, 100)),
) {
  let (collateral, debt) = vals
  min_repay_to_restore(collateral, debt, 150) == 0
}

test prop_repay_restores_health(
  vals via fuzz.both(fuzz.int_between(1, 100), fuzz.int_between(101, 200)),
) {
  let (collateral, debt) = vals
  let repay = min_repay_to_restore(collateral, debt, 150)
  repay == 0 || healthy_after_repay(collateral, debt, repay, 150)
}

test prop_full_repay_always_healthy(
  vals via fuzz.both(fuzz.int_between(1, 1000), fuzz.int_between(1, 1000)),
) {
  let (collateral, debt) = vals
  // Repay all but 1 lovelace
  let repay = debt - 1
  healthy_after_repay(collateral, debt, repay, 0)
}

test prop_min_repay_non_negative(
  vals via fuzz.both(fuzz.int_between(1, 1000), fuzz.int_between(1, 1000)),
) {
  let (collateral, debt) = vals
  min_repay_to_restore(collateral, debt, 150) >= 0
}
